message.content:
@startuml
hide footbox
skinparam sequenceMessageAlign left
skinparam ParticipantPadding 30
skinparam BoxPadding 10

participant User_App
participant WebRTC_GW
participant SkyWay_Server
participant Target_Peer

User_App -> WebRTC_GW: POST /peers
{
  key: "YOUR_API_KEY",
  domain: "localhost",
  turn: true,
  peer_id: "media_caller"
}
WebRTC_GW --> User_App: 201 Created
{
  command_type: "PEERS_CREATE",
  params: {
    peer_id: "media_caller",
    token: "pt-be747373-5762-401f-a526-01fa44d98a11"
  }
}

User_App -> WebRTC_GW: GET /peers/media_caller/events?
token=pt-be747373-5762-401f-a526-01fa44d98a11
WebRTC_GW -> SkyWay_Server: CREATE PEER
SkyWay_Server --> WebRTC_GW: SUCCESS
(to bind peer_id)
WebRTC_GW --> User_App: 200 OK
{
  "event": "OPEN",
  params: {
    peer_id: "media_caller",
    token: "pt-be747373-5762-401f-a526-01fa44d98a11"
  }
}

User_App -> WebRTC_GW: POST /media
{
  is_video=true
}
WebRTC_GW --> User_App: 201 Created
{
  ip_v4: "172.16.1.106",
  media_id: "ip-9856040d-bd3e-4b33-b121-e3435842e5fc",
  port: 50003
}

User_App -> WebRTC_GW: POST /media
{
  is_video=false
}
WebRTC_GW --> User_App: 201 Created
{
  ip_v4: "172.16.1.106",
  media_id: "au-a46c482c-9d9c-4e12-a52a-c927ec33793e",
  port: 50004
}

User_App -> WebRTC_GW: POST /media/rtcp
{}
WebRTC_GW --> User_App: 201 Created
{
  "rtcp_id": "rc-970f2e5d-4da0-43e7-92b6-796678c10a4d",
  "port": 50003,
  "ip_v4": "172.16.1.106"
}

User_App -> WebRTC_GW: POST /media/rtcp
{}
WebRTC_GW --> User_App: 201 Created
{
  "rtcp_id": "rc-4044658s-dee5-4aac-a60a-ad133bab4f92",
  "port": 50004,
  "ip_v4": "172.16.1.106"
}

User_App -> WebRTC_GW: POST /media/connections
{
  peer_id: "media_caller",
  token: "pt-be747373-5762-401f-a526-01fa44d98a11",
  target_id: "media_callee",
  constraints: {
    video: true,
    videoReceiveEnabled: true,
    audio: true,
    audioReceiveEnabled: true,
    video_params: {
      band_width: 1500,
      codec: "H264",
      media_id: "ip-9856040d-bd3e-4b33-b121-e3435842e5fc",
      rtcp_id: "rc-970f2e5d-4da0-43e7-92b6-796678c10a4d",
      payload_type: 100
    },
    audio_params: {
      band_width: 1500,
      codec: "opus",
      media_id: "au-a46c482c-9d9c-4e12-a52a-c927ec33793e",
      rtcp_id: "rc-4044658s-dee5-4aac-a60a-ad133bab4f92",
      payload_type: 111
    }
  },
  redirect_params: {
    video: {
      ip_v4: "172.16.1.105",
      port: 20000
    },
    video_rtcp: {
      ip_v4: "172.16.1.105",
      port: 20010
    },
    audio: {
      ip_v4: "172.16.1.105",
      port: 20001
    },
    audio_rtcp: {
      ip_v4: "172.16.1.105",
      port: 20011
    }
  }
}
WebRTC_GW --> User_App: 201 Created
{
  command_type: "MEDIA_CONNECTION_CREATE",
  params: {
    media_connection_id: "mc-55f0b9c7-77c7-42d7-b21b-a6a6cb3cfe3a"
  }
}

User_App -> WebRTC_GW: GET /media/connections
/mc-55f0b9c7-77c7-42d7-b21b-a6a6cb3cfe3a/events
WebRTC_GW --> User_App: 200 OK
{
  event: "READY"
}

loop
  User_App -> WebRTC_GW: send RTP Video to 172.16.1.106:50001
  WebRTC_GW -> Target_Peer: redirect Video with MediaStream

  User_App -> WebRTC_GW: send RTP Audio to 172.16.1.106:50002
  WebRTC_GW -> Target_Peer: redirect Audio with MediaStream

  User_App -> WebRTC_GW: send RTCP for Video to 172.16.1.106:50003
  WebRTC_GW -> Target_Peer: redirect RTCP with MediaStream

  User_App -> WebRTC_GW: send RTCP for Audio to 172.16.1.106:50004
  WebRTC_GW -> Target_Peer: redirect RTCP with MediaStream

  User_App -> WebRTC_GW: redirect RTP Video to 172.16.1.105:20000
  WebRTC_GW -> Target_Peer: recv Video with MediaStream

  User_App -> WebRTC_GW: redirect RTP Audio to 172.16.1.105:20001
  WebRTC_GW -> Target_Peer: recv Audio with MediaStream

  User_App -> WebRTC_GW: redirect RTCP for Video to 172.16.1.105:20010
  WebRTC_GW -> Target_Peer: recv RTCP for Video with MediaStream

  User_App -> WebRTC_GW: redirect RTCP for Audio to 172.16.1.105:20011
  WebRTC_GW -> Target_Peer: recv RTCP for Audio with MediaStream
end

User_App -> WebRTC_GW: Delete /media/connections
/mc-55f0b9c7-77c7-42d7-b21b-a6a6cb3cfe3a
WebRTC_GW -> Target_Peer: Close MediaStream
WebRTC_GW -> Target_Peer: erase Video object
and Audio object
WebRTC_GW --> User_App: 204 No Content

User_App -> WebRTC_GW: Delete /peers/media_caller?token=pt-be747373-5762-401f-a526-01fa44d98a11
WebRTC_GW -> SkyWay_Server: disconnect
WebRTC_GW --> User_App: 204 No Content
@enduml
